import{_ as i,o as t,c as r,a5 as a}from"./chunks/framework.BytL3m0N.js";const p=JSON.parse('{"title":"Security","description":"","frontmatter":{},"headers":[],"relativePath":"reference/security/index.md","filePath":"reference/security/index.md"}'),s={name:"reference/security/index.md"};function n(o,e,l,u,d,c){return t(),r("div",null,[...e[0]||(e[0]=[a('<h1 id="security" tabindex="-1">Security <a class="header-anchor" href="#security" aria-label="Permalink to &quot;Security&quot;">​</a></h1><p>The Platform Mesh project hosts many different user-facing repositories under the <a href="https://github.com/platform-mesh" target="_blank" rel="noreferrer"><code>platform-mesh</code></a> GitHub organization. This page describes how the project receives reports of, triages, remediates, and discloses security vulnerabilities.</p><p>The scope of this document is:</p><ul><li>Vulnerabilities reported through the official security process described in the <a href="https://github.com/platform-mesh/.github/blob/main/SECURITY.md" target="_blank" rel="noreferrer">SECURITY.md</a> file</li><li>Vulnerabilities discovered in third-party dependencies</li></ul><h2 id="security-response-team" tabindex="-1">Security response team <a class="header-anchor" href="#security-response-team" aria-label="Permalink to &quot;Security response team&quot;">​</a></h2><p>A dedicated Security Response Team is responsible for all vulnerability-related activity. Responsibilities include receiving and acknowledging vulnerability reports, reviewing automated findings, coordinating fixes, publishing GitHub Security Advisories and CVEs, and communicating with reporters and users throughout the process.</p><p>For an up-to-date list of all team members, see <a href="https://github.com/orgs/platform-mesh/teams/security" target="_blank" rel="noreferrer">the <code>platform-mesh/security</code> GitHub team</a>.</p><h2 id="staying-up-to-date" tabindex="-1">Staying up to date <a class="header-anchor" href="#staying-up-to-date" aria-label="Permalink to &quot;Staying up to date&quot;">​</a></h2><p>Information about security fixes in Platform Mesh and updates to vulnerable dependencies is published in <strong>the changelog</strong> with each release.</p><p>Security fixes in Platform Mesh are also announced on the <a href="https://lists.neonephos.org/g/PlatformMesh-Announcement" target="_blank" rel="noreferrer"><code>PlatformMesh-Announcement</code> mailing list</a>. For high and critical severity vulnerabilities, a pre-announcement is sent to the mailing list at least 24 hours before the release.</p><p>To receive security announcements:</p><ul><li><a href="https://lists.neonephos.org/g/PlatformMesh-Announcement" target="_blank" rel="noreferrer">Subscribe to the <code>PlatformMesh-Announcement</code> mailing list</a> for security announcements and pre-announcements.</li><li><a href="https://github.blog/changelog/2018-11-26-watch-releases/" target="_blank" rel="noreferrer">Subscribe to release notifications</a> for relevant Platform Mesh repositories.</li></ul><h2 id="reporting-vulnerabilities" tabindex="-1">Reporting vulnerabilities <a class="header-anchor" href="#reporting-vulnerabilities" aria-label="Permalink to &quot;Reporting vulnerabilities&quot;">​</a></h2><p>Do <strong>NOT</strong>:</p><ul><li>Report potential security vulnerabilities through GitHub issues or other public channels</li><li>Contact Security Response Team members directly</li></ul><p>Instead, follow the process explained in the <a href="https://github.com/platform-mesh/.github/blob/main/SECURITY.md" target="_blank" rel="noreferrer">SECURITY.md</a> file.</p><p>Platform Mesh follows the principle of <a href="https://en.wikipedia.org/wiki/Coordinated_vulnerability_disclosure" target="_blank" rel="noreferrer">Coordinated Vulnerability Disclosure</a>. Reporters are asked to:</p><ul><li>Allow reasonable time to investigate and address the issue before making any information public.</li><li>Make a good faith effort to avoid privacy violations, data destruction, and disruption of services.</li><li>Not exploit the vulnerability beyond what is necessary to verify it.</li></ul><p>The Security Response Team commits to:</p><ul><li>Acknowledging receipt of the vulnerability report.</li><li>Providing an estimated timeline for a fix.</li><li>Notifying the reporter when the vulnerability is resolved.</li></ul><h2 id="handling-security-vulnerabilities" tabindex="-1">Handling security vulnerabilities <a class="header-anchor" href="#handling-security-vulnerabilities" aria-label="Permalink to &quot;Handling security vulnerabilities&quot;">​</a></h2><h3 id="direct-vulnerability-reports" tabindex="-1">Direct vulnerability reports <a class="header-anchor" href="#direct-vulnerability-reports" aria-label="Permalink to &quot;Direct vulnerability reports&quot;">​</a></h3><p>When a vulnerability report arrives, the Security Response Team reviews it and, if needed, takes action to fix or mitigate the vulnerability in a private fork of the affected repository. Once ready, the fix is included in the next release. For vulnerabilities rated high or critical, an out-of-band release is performed. Depending on the affected repository&#39;s release policy, the security fix is backported to previous releases.</p><p><strong>NOTE:</strong> Reports that consist solely of automated scanner output — without proof that the vulnerability is reachable in Platform Mesh — require additional investigation before being treated as confirmed vulnerabilities. The Security Response Team evaluates whether the affected code path is actually invoked in Platform Mesh. If the vulnerability is confirmed to be reachable, it is handled as a confirmed vulnerability. If not, the reporter is notified and the report is closed.</p><h4 id="low-and-medium-severity-vulnerabilities" tabindex="-1">Low and medium severity vulnerabilities <a class="header-anchor" href="#low-and-medium-severity-vulnerabilities" aria-label="Permalink to &quot;Low and medium severity vulnerabilities&quot;">​</a></h4><p>In most cases, vulnerabilities rated low or medium are <strong>not</strong> pre-announced. Full details are disclosed when the release containing the fix is published. Platform Mesh does not issue a CVE number for these vulnerabilities, but a GitHub Security Advisory is published alongside the release.</p><h4 id="high-and-critical-severity-vulnerabilities" tabindex="-1">High and critical severity vulnerabilities <a class="header-anchor" href="#high-and-critical-severity-vulnerabilities" aria-label="Permalink to &quot;High and critical severity vulnerabilities&quot;">​</a></h4><p>Vulnerabilities rated high and critical are communicated differently from low and medium severity vulnerabilities:</p><ul><li>A security release pre-announcement is sent at least 24 hours before the release without disclosing details about the vulnerability.</li><li>Security releases are created according to the timeline stated in the pre-announcement.</li><li>Details about vulnerabilities are published 24–48 hours after the security releases are created.</li></ul><p>Both a CVE number and a GitHub Security Advisory are issued for these vulnerabilities.</p><h3 id="vulnerabilities-in-dependencies" tabindex="-1">Vulnerabilities in dependencies <a class="header-anchor" href="#vulnerabilities-in-dependencies" aria-label="Permalink to &quot;Vulnerabilities in dependencies&quot;">​</a></h3><p>Like every project that uses external dependencies, Platform Mesh is potentially vulnerable to issues discovered in those dependencies. In many cases, those vulnerabilities are not actually exploitable within Platform Mesh. To minimize risks, the project uses tooling that automatically updates affected dependencies when a vulnerability is discovered or published.</p><p>Updates to vulnerable dependencies are typically included in regular scheduled releases and communicated exclusively through the changelog. Vulnerabilities in dependencies that are rated high or critical and confirmed to be exploitable in Platform Mesh are an exception and are handled following the same process as <a href="#high-and-critical-severity-vulnerabilities">high and critical severity vulnerabilities</a>.</p><p>Platform Mesh does not issue a CVE number or GitHub Security Advisory for vulnerabilities in dependencies, because a CVE number or advisory already exists from the upstream project.</p><h3 id="information-disclosure" tabindex="-1">Information disclosure <a class="header-anchor" href="#information-disclosure" aria-label="Permalink to &quot;Information disclosure&quot;">​</a></h3><p>Public disclosure happens through GitHub Security Advisories. Each advisory contains a description, affected versions, patched versions, and CVSS severity. For high and critical severity vulnerabilities, a CVE number is also issued. The fix is highlighted in the changelog under a dedicated <strong>Security Fixes</strong> section. The advisory is automatically published to the GitHub Advisory Database, so downstream projects are also notified via GitHub.</p><h2 id="security-posture" tabindex="-1">Security posture <a class="header-anchor" href="#security-posture" aria-label="Permalink to &quot;Security posture&quot;">​</a></h2><p>The Platform Mesh project runs regular automated checks to ensure a strong security posture in all user-facing repositories. OpenSSF Scorecard is used for this purpose. For more details, see the <a href="./scorecard.html">OpenSSF Scorecard document</a>.</p><h2 id="related" tabindex="-1">Related <a class="header-anchor" href="#related" aria-label="Permalink to &quot;Related&quot;">​</a></h2><ul><li><a href="./scorecard.html">OpenSSF Scorecard</a> — automated security posture checks for Platform Mesh repositories</li><li><a href="https://github.com/platform-mesh/.github/blob/main/SECURITY.md" target="_blank" rel="noreferrer">SECURITY.md</a> — the reporting process referenced throughout this page</li></ul>',40)])])}const b=i(s,[["render",n]]);export{p as __pageData,b as default};
